{"filesWritten":[{"path":"src/components/LoginButton.tsx","content":"import { useEffect, useRef } from 'react';

export function LoginButton({ onLogin }: { onLogin: () => void }) {
  const ref = useRef<HTMLButtonElement>(null);
  useEffect(() => {
    const node = ref.current;
    if (!node) return;
    const handler = () => onLogin();
    node.addEventListener('touchend', handler, { passive: false });
    return () => node.removeEventListener('touchend', handler);
  }, [onLogin]);
  return <button ref={ref} onClick={onLogin}>Log in</button>;
}
